mod checkpoint;
mod config;
mod git;
mod pty;
mod session;
mod trail;
mod watcher;

use std::collections::HashSet;
use std::sync::Mutex;
use tauri::{Emitter, State};

struct AppState {
    pty_manager: pty::PtyManager,
    watched_repos: HashSet<String>,
}

#[tauri::command]
fn list_repos() -> Result<Vec<git::RepoInfo>, String> {
    let repo_paths = config::discover_repos();
    let mut repos = Vec::new();
    for path in repo_paths {
        match git::get_repo_info(&path) {
            Ok(info) => repos.push(info),
            Err(e) => eprintln!("Skipping repo {}: {}", path, e),
        }
    }
    Ok(repos)
}

#[tauri::command]
fn list_checkpoints(
    repo_path: String,
    branch: String,
) -> Result<Vec<checkpoint::CheckpointSummary>, String> {
    let repo = git::open_repo(&repo_path)?;
    checkpoint::list_checkpoints(&repo, &branch)
}

#[tauri::command]
fn get_transcript(
    repo_path: String,
    checkpoint_id: String,
    session_index: u32,
) -> Result<Vec<session::TranscriptMessage>, String> {
    let repo = git::open_repo(&repo_path)?;

    let prefix = &checkpoint_id[..2];
    let suffix = &checkpoint_id[2..];
    let session_dir = format!("{}/{}/{}", prefix, suffix, session_index);

    // Read the checkpoint metadata to find the actual transcript path
    let meta_path = format!("{}/{}/metadata.json", prefix, suffix);
    let transcript_path = read_blob(&repo, &meta_path)
        .ok()
        .and_then(|meta_content| {
            let meta: serde_json::Value = serde_json::from_str(&meta_content).ok()?;
            let sessions = meta.get("sessions")?.as_array()?;
            let session = sessions.get(session_index as usize)?;
            session.get("transcript")?.as_str().map(|s| s.to_string())
        });

    // Build candidates: metadata path (may be absolute from tree root), then fallbacks
    let mut candidates = Vec::new();
    if let Some(ref path) = transcript_path {
        // Paths from metadata may be absolute (leading /) — strip it for tree lookup
        candidates.push(path.trim_start_matches('/').to_string());
    }
    candidates.push(format!("{}/full.jsonl", session_dir));
    candidates.push(format!("{}/transcript.jsonl", session_dir));

    for path in &candidates {
        if let Ok(content) = read_blob(&repo, path) {
            return Ok(session::read_transcript(&content));
        }
    }

    Err(format!("Transcript not found for checkpoint {} session {}", checkpoint_id, session_index))
}

/// Read a blob from the entire/checkpoints/v1 branch by path
fn read_blob(repo: &git2::Repository, path: &str) -> Result<String, String> {
    let branch_ref = repo
        .find_branch("entire/checkpoints/v1", git2::BranchType::Local)
        .map_err(|e| format!("No checkpoint branch: {}", e))?;

    let commit = branch_ref
        .get()
        .peel_to_commit()
        .map_err(|e| format!("Failed to peel: {}", e))?;

    let tree = commit
        .tree()
        .map_err(|e| format!("Failed to get tree: {}", e))?;

    let entry = tree
        .get_path(std::path::Path::new(path))
        .map_err(|e| format!("Path not found: {}", e))?;

    let blob = repo
        .find_blob(entry.id())
        .map_err(|e| format!("Failed to read blob: {}", e))?;

    std::str::from_utf8(blob.content())
        .map(|s| s.to_string())
        .map_err(|e| format!("Invalid UTF-8: {}", e))
}

#[tauri::command]
fn list_sessions(repo_path: String) -> Result<Vec<session::SessionState>, String> {
    session::list_active_sessions(&repo_path)
}

#[tauri::command]
fn spawn_agent(
    repo_path: String,
    agent: String,
    app: tauri::AppHandle,
    state: State<'_, Mutex<AppState>>,
) -> Result<String, String> {
    let app_handle = app.clone();
    let state = state.lock().map_err(|_| "State lock error".to_string())?;

    state.pty_manager.spawn(&agent, &repo_path, move |session_id, data| {
        let _ = app_handle.emit("pty-output", serde_json::json!({
            "sessionId": session_id,
            "data": data,
        }));
    })
}

#[tauri::command]
fn pty_input(
    session_id: String,
    data: String,
    state: State<'_, Mutex<AppState>>,
) -> Result<(), String> {
    let state = state.lock().map_err(|_| "State lock error".to_string())?;
    state.pty_manager.write(&session_id, data.as_bytes())
}

#[tauri::command]
fn pty_resize(
    session_id: String,
    cols: u16,
    rows: u16,
    state: State<'_, Mutex<AppState>>,
) -> Result<(), String> {
    let state = state.lock().map_err(|_| "State lock error".to_string())?;
    state.pty_manager.resize(&session_id, cols, rows)
}

#[tauri::command]
fn kill_pty(
    session_id: String,
    state: State<'_, Mutex<AppState>>,
) -> Result<(), String> {
    let state = state.lock().map_err(|_| "State lock error".to_string())?;
    state.pty_manager.kill(&session_id)
}

#[tauri::command]
fn list_trails(repo_path: String) -> Result<Vec<trail::Trail>, String> {
    let repo = git::open_repo(&repo_path)?;
    trail::list_trails(&repo)
}

#[derive(serde::Serialize)]
struct FileDiff {
    path: String,
    status: String, // "added", "modified", "deleted"
    hunks: Vec<DiffHunk>,
}

#[derive(serde::Serialize)]
struct DiffHunk {
    header: String,
    lines: Vec<DiffLine>,
}

#[derive(serde::Serialize)]
struct DiffLine {
    kind: String, // "add", "delete", "context"
    content: String,
}

#[tauri::command]
fn get_checkpoint_diff(
    repo_path: String,
    commit_sha: String,
) -> Result<Vec<FileDiff>, String> {
    if commit_sha.is_empty() {
        return Err("No commit SHA available for this checkpoint".to_string());
    }

    let repo = git::open_repo(&repo_path)?;
    let oid = git2::Oid::from_str(&commit_sha)
        .map_err(|e| format!("Invalid commit SHA: {}", e))?;
    let commit = repo
        .find_commit(oid)
        .map_err(|e| format!("Commit not found: {}", e))?;

    let tree = commit
        .tree()
        .map_err(|e| format!("Failed to get tree: {}", e))?;

    // Diff against parent (or empty tree if no parent)
    let parent_tree = commit
        .parent(0)
        .ok()
        .and_then(|p| p.tree().ok());

    let diff = repo
        .diff_tree_to_tree(parent_tree.as_ref(), Some(&tree), None)
        .map_err(|e| format!("Failed to compute diff: {}", e))?;

    let mut files: Vec<FileDiff> = Vec::new();

    diff.print(git2::DiffFormat::Patch, |delta, hunk, line| {
        let path = delta
            .new_file()
            .path()
            .or_else(|| delta.old_file().path())
            .map(|p| p.to_string_lossy().to_string())
            .unwrap_or_default();

        let status = match delta.status() {
            git2::Delta::Added => "added",
            git2::Delta::Deleted => "deleted",
            _ => "modified",
        };

        // Ensure we have a FileDiff entry for this path
        if files.last().map_or(true, |f| f.path != path) {
            files.push(FileDiff {
                path: path.clone(),
                status: status.to_string(),
                hunks: Vec::new(),
            });
        }

        let file = files.last_mut().unwrap();

        // New hunk
        if let Some(h) = hunk {
            let header = std::str::from_utf8(h.header()).unwrap_or("").to_string();
            if file.hunks.last().map_or(true, |last| last.header != header) {
                file.hunks.push(DiffHunk {
                    header,
                    lines: Vec::new(),
                });
            }
        }

        // Diff line
        if let Some(current_hunk) = file.hunks.last_mut() {
            let kind = match line.origin() {
                '+' => "add",
                '-' => "delete",
                ' ' => "context",
                _ => return true,
            };
            let content = std::str::from_utf8(line.content()).unwrap_or("").to_string();
            current_hunk.lines.push(DiffLine {
                kind: kind.to_string(),
                content,
            });
        }

        true
    })
    .map_err(|e| format!("Failed to print diff: {}", e))?;

    Ok(files)
}

#[tauri::command]
fn watch_repo(
    repo_path: String,
    app: tauri::AppHandle,
    state: State<'_, Mutex<AppState>>,
) -> Result<(), String> {
    let mut app_state = state.lock().map_err(|_| "State lock error".to_string())?;

    // Don't double-watch
    if app_state.watched_repos.contains(&repo_path) {
        return Ok(());
    }
    app_state.watched_repos.insert(repo_path.clone());

    let app_handle = app.clone();
    let repo_path_for_closure = repo_path.clone();
    watcher::watch_repo(&repo_path, move |event| {
        let event_name = match event {
            watcher::WatchEvent::CheckpointChanged => "checkpoint-changed",
            watcher::WatchEvent::SessionChanged(_) => "session-changed",
            watcher::WatchEvent::ConfigChanged => "config-changed",
        };
        let _ = app_handle.emit(event_name, serde_json::json!({
            "repoPath": repo_path_for_closure,
        }));
    })?;

    Ok(())
}

#[cfg_attr(mobile, tauri::mobile_entry_point)]
pub fn run() {
    tauri::Builder::default()
        .plugin(tauri_plugin_opener::init())
        .plugin(tauri_plugin_window_state::Builder::default().build())
        .manage(Mutex::new(AppState {
            pty_manager: pty::PtyManager::new(),
            watched_repos: HashSet::new(),
        }))
        .setup(|app| {
            // System tray
            use tauri::menu::{MenuBuilder, MenuItemBuilder};
            use tauri::tray::TrayIconBuilder;
            use tauri::Manager;

            let show = MenuItemBuilder::with_id("show", "Show Entire").build(app)?;
            let quit = MenuItemBuilder::with_id("quit", "Quit").build(app)?;
            let menu = MenuBuilder::new(app)
                .item(&show)
                .separator()
                .item(&quit)
                .build()?;

            let _tray = TrayIconBuilder::new()
                .tooltip("Entire Desktop")
                .menu(&menu)
                .on_menu_event(move |app, event| {
                    match event.id().as_ref() {
                        "show" => {
                            if let Some(window) = app.get_webview_window("main") {
                                let _ = window.show();
                                let _ = window.set_focus();
                            }
                        }
                        "quit" => {
                            app.exit(0);
                        }
                        _ => {}
                    }
                })
                .on_tray_icon_event(|tray, event| {
                    if let tauri::tray::TrayIconEvent::Click { .. } = event {
                        let app = tray.app_handle();
                        if let Some(window) = app.get_webview_window("main") {
                            let _ = window.show();
                            let _ = window.set_focus();
                        }
                    }
                })
                .build(app)?;

            Ok(())
        })
        .invoke_handler(tauri::generate_handler![
            list_repos,
            list_checkpoints,
            get_transcript,
            get_checkpoint_diff,
            list_sessions,
            spawn_agent,
            pty_input,
            pty_resize,
            kill_pty,
            list_trails,
            watch_repo,
        ])
        .run(tauri::generate_context!())
        .expect("error while running tauri application");
}

