@import "tailwindcss";

@theme {
  --color-bg: #0d0d0d;
  --color-bg-raised: #111111;
  --color-bg-overlay: #141414;
  --color-bg-hover: #1a1a1a;
  --color-bg-active: #1c1c2e;

  --color-border: #222222;
  --color-border-subtle: #1a1a1a;
  --color-border-hover: #333333;

  --color-fg: #e4e4e7;
  --color-fg-muted: #888888;
  --color-fg-subtle: #555555;
  --color-fg-faint: #333333;

  --color-accent: #7c3aed;
  --color-accent-hover: #6d28d9;
  --color-accent-fg: #a78bfa;
  --color-accent-bg: #1a1528;

  --color-green: #4ade80;
  --color-green-bg: #1a2e1a;
  --color-red: #f87171;
  --color-red-bg: #2e1a1a;
  --color-yellow: #fbbf24;
  --color-yellow-bg: #2e2a1a;
  --color-blue: #60a5fa;
  --color-blue-bg: #1a2238;

  --font-mono: "SF Mono", "Fira Code", "Cascadia Code", monospace;
}

html,
body,
#root {
  height: 100%;
  margin: 0;
  padding: 0;
  overflow: hidden;
  background: var(--color-bg);
  color: var(--color-fg);
  font-family: -apple-system, BlinkMacSystemFont, "SF Pro Text", "Segoe UI",
    sans-serif;
}

/* Scrollbar */
::-webkit-scrollbar {
  width: 6px;
}
::-webkit-scrollbar-track {
  background: transparent;
}
::-webkit-scrollbar-thumb {
  background: var(--color-fg-faint);
  border-radius: 3px;
}
::-webkit-scrollbar-thumb:hover {
  background: var(--color-fg-subtle);
}

/* Terminal cursor blink */
@keyframes blink {
  50% {
    opacity: 0;
  }
}

/* Pulse animation for active indicators */
@keyframes pulse {
  0%,
  100% {
    opacity: 1;
  }
  50% {
    opacity: 0.4;
  }
}

import { getCurrentWindow } from "@tauri-apps/api/window";

interface TitleBarProps {
  title: string;
}

export function TitleBar({ title }: TitleBarProps) {
  const appWindow = getCurrentWindow();

  return (
    <div
      className="flex h-[38px] shrink-0 items-center border-b border-border bg-bg-raised px-4"
      data-tauri-drag-region
    >
      {/* macOS traffic lights */}
      <div className="mr-4 flex gap-2">
        <button
          onClick={() => appWindow.close()}
          className="group flex h-3 w-3 items-center justify-center rounded-full bg-[#ff5f57] transition-opacity hover:opacity-80"
        >
          <span className="hidden text-[8px] leading-none text-black/60 group-hover:inline">
            ×
          </span>
        </button>
        <button
          onClick={() => appWindow.minimize()}
          className="group flex h-3 w-3 items-center justify-center rounded-full bg-[#febc2e] transition-opacity hover:opacity-80"
        >
          <span className="hidden text-[8px] leading-none text-black/60 group-hover:inline">
            −
          </span>
        </button>
        <button
          onClick={() => appWindow.toggleMaximize()}
          className="group flex h-3 w-3 items-center justify-center rounded-full bg-[#28c840] transition-opacity hover:opacity-80"
        >
          <span className="hidden text-[8px] leading-none text-black/60 group-hover:inline">
            +
          </span>
        </button>
      </div>
      <span className="text-xs text-fg-muted" data-tauri-drag-region>
        {title}
      </span>
    </div>
  );
}

