 12→function formatTokens(usage: CheckpointSummary["token_usage"]): string | null {
 13→  if (!usage) return null;
 14→  const total = usage.input_tokens + usage.output_tokens;
 15→  if (total >= 1000) return `${(total / 1000).toFixed(1)}k tokens`;
 16→  return `${total} tokens`;
 17→}
 18→
 19→function timeAgo(isoDate: string): string {
 20→  const diff = Date.now() - new Date(isoDate).getTime();
 21→  const mins = Math.floor(diff / 60000);
 22→  if (mins < 1) return "just now";
 23→  if (mins < 60) return `${mins}m ago`;
 24→  const hours = Math.floor(mins / 60);
 25→  if (hours < 24) return `${hours}h ago`;
 26→  return `${Math.floor(hours / 24)}d ago`;
 27→}
