 33→function timeAgo(isoDate: string): string {
 34→  const diff = Date.now() - new Date(isoDate).getTime();
 35→  const mins = Math.floor(diff / 60000);
 36→  if (mins < 1) return "just now";
 37→  if (mins < 60) return `${mins}m ago`;
 38→  const hours = Math.floor(mins / 60);
 39→  if (hours < 24) return `${hours}h ago`;
 40→  return `${Math.floor(hours / 24)}d ago`;
 41→}
