  1→import { useState, useEffect } from "react";
  2→import { Sidebar } from "./features/repos/Sidebar";
  3→import { TitleBar } from "./components/TitleBar";
  4→import { TabBar } from "./components/TabBar";
  5→import { CheckpointList } from "./features/checkpoints/CheckpointList";
  6→import { TranscriptView } from "./features/transcripts/TranscriptView";
  7→import { TrailList } from "./features/trails/TrailList";
  8→import { DiffView } from "./features/diff/DiffView";
  9→import { TerminalPanel } from "./features/terminal/TerminalPanel";
 10→import { useLiveUpdates } from "./hooks/use-live-updates";
 11→import type { BranchInfo, CheckpointSummary, WorktreeInfo } from "./lib/ipc";
 12→
 13→export interface Tab {
 14→  id: string;
 15→  branch: string;
 16→  repoPath: string;
 17→  worktree: WorktreeInfo | null;
 18→  hasActiveSession: boolean;
 19→}
 20→
 21→export default function App() {
 22→  const [tabs, setTabs] = useState<Tab[]>([
 23→    {
 24→      id: "main",
 25→      branch: "main",
 26→      repoPath: "",
 27→      worktree: null,
 28→      hasActiveSession: false,
 29→    },
 30→  ]);
 31→  const [activeTabId, setActiveTabId] = useState("main");
 32→  const [terminalHeight, setTerminalHeight] = useState(
 33→    () => Number(localStorage.getItem("entire:terminal-height")) || 220
 34→  );
 35→  const [isTerminalOpen, setIsTerminalOpen] = useState(
 36→    () => localStorage.getItem("entire:terminal-open") !== "false"
 37→  );
 38→  const [innerTab, setInnerTab] = useState<
 39→    "checkpoints" | "transcript" | "trails" | "diff"
 40→  >("checkpoints");
 41→  const [selectedCheckpoint, setSelectedCheckpoint] =
 42→    useState<CheckpointSummary | null>(null);
 43→
 44→  const activeTab = tabs.find((t) => t.id === activeTabId) ?? tabs[0];
 45→
 46→  // Live updates — watch active repo for checkpoint/session changes
 47→  useLiveUpdates(activeTab.repoPath);
 48→
 49→  // Persist UI state to localStorage
 50→  useEffect(() => {
 51→    localStorage.setItem("entire:terminal-height", String(terminalHeight));
 52→  }, [terminalHeight]);
 53→  useEffect(() => {
 54→    localStorage.setItem("entire:terminal-open", String(isTerminalOpen));
 55→  }, [isTerminalOpen]);
 56→
 57→  // Keyboard shortcuts
 58→  useEffect(() => {
 59→    function onKeyDown(e: KeyboardEvent) {
 60→      const meta = e.metaKey || e.ctrlKey;
 61→
 62→      // Cmd+K = focus search
 63→      if (meta && e.key === "k") {
 64→        e.preventDefault();
 65→        document.querySelector<HTMLInputElement>('input[placeholder*="Search"]')?.focus();
 66→      }
 67→      // Ctrl+` = toggle terminal
 68→      if (e.ctrlKey && e.key === "`") {
 69→        e.preventDefault();
 70→        setIsTerminalOpen((v) => !v);
 71→      }
 72→      // Cmd+W = close active tab
 73→      if (meta && e.key === "w") {
 74→        e.preventDefault();
 75→        handleCloseTab(activeTabId);
 76→      }
 77→      // Cmd+1-9 = switch to tab by index
 78→      if (meta && e.key >= "1" && e.key <= "9") {
 79→        e.preventDefault();
 80→        const idx = parseInt(e.key) - 1;
 81→        if (idx < tabs.length) {
 82→          setActiveTabId(tabs[idx].id);
 83→        }
 84→      }
 85→      // Cmd+[ / Cmd+] = prev/next tab
 86→      if (meta && e.key === "[") {
 87→        e.preventDefault();
 88→        const idx = tabs.findIndex((t) => t.id === activeTabId);
 89→        if (idx > 0) setActiveTabId(tabs[idx - 1].id);
 90→      }
 91→      if (meta && e.key === "]") {
 92→        e.preventDefault();
 93→        const idx = tabs.findIndex((t) => t.id === activeTabId);
 94→        if (idx < tabs.length - 1) setActiveTabId(tabs[idx + 1].id);
 95→      }
 96→    }
 97→    window.addEventListener("keydown", onKeyDown);
 98→    return () => window.removeEventListener("keydown", onKeyDown);
 99→  }, [activeTabId, tabs]);
100→
101→  function handleBranchSelect(branch: BranchInfo, repoPath: string) {
102→    const existing = tabs.find(
103→      (t) => t.branch === branch.name && t.repoPath === repoPath
104→    );
105→    if (existing) {
106→      setActiveTabId(existing.id);
107→    } else {
108→      const newTab: Tab = {
109→        id: `${repoPath}:${branch.name}`,
110→        branch: branch.name,
111→        repoPath,
112→        worktree: null,
113→        hasActiveSession: false,
114→      };
115→      setTabs([...tabs, newTab]);
116→      setActiveTabId(newTab.id);
117→    }
118→  }
119→
120→  function handleWorktreeSelect(wt: WorktreeInfo, repoPath: string) {
121→    const existing = tabs.find(
122→      (t) => t.branch === wt.branch && t.repoPath === repoPath
123→    );
124→    if (existing) {
125→      setActiveTabId(existing.id);
126→    } else {
127→      const newTab: Tab = {
128→        id: `${repoPath}:${wt.branch}`,
129→        branch: wt.branch,
130→        repoPath,
131→        worktree: wt,
132→        hasActiveSession: false,
133→      };
134→      setTabs([...tabs, newTab]);
135→      setActiveTabId(newTab.id);
136→    }
137→  }
138→
139→  function handleCloseTab(tabId: string) {
140→    if (tabs.length <= 1) return;
141→    const idx = tabs.findIndex((t) => t.id === tabId);
142→    const newTabs = tabs.filter((t) => t.id !== tabId);
143→    setTabs(newTabs);
144→    if (activeTabId === tabId) {
145→      setActiveTabId(newTabs[Math.max(0, idx - 1)].id);
146→    }
147→  }
148→
149→  function handleResizeStart(e: React.MouseEvent) {
150→    e.preventDefault();
151→    const startY = e.clientY;
152→    const startHeight = terminalHeight;
153→
154→    function onMouseMove(ev: MouseEvent) {
155→      const delta = startY - ev.clientY;
156→      setTerminalHeight(Math.max(100, Math.min(600, startHeight + delta)));
157→    }
158→    function onMouseUp() {
159→      window.removeEventListener("mousemove", onMouseMove);
160→      window.removeEventListener("mouseup", onMouseUp);
161→    }
162→    window.addEventListener("mousemove", onMouseMove);
163→    window.addEventListener("mouseup", onMouseUp);
164→  }
165→
166→  return (
167→    <div className="flex h-screen flex-col">
168→      <TitleBar title={`Entire — ${activeTab?.branch ?? ""}`} />
169→
170→      <div className="flex flex-1 overflow-hidden">
171→        {/* Sidebar */}
172→        <Sidebar
173→          activeTab={activeTab}
174→          onBranchSelect={handleBranchSelect}
175→          onWorktreeSelect={handleWorktreeSelect}
176→        />
177→
178→        {/* Main content */}
179→        <div className="flex flex-1 flex-col overflow-hidden">
180→          <TabBar
181→            tabs={tabs}
182→            activeTabId={activeTabId}
183→            onSelectTab={setActiveTabId}
184→            onCloseTab={handleCloseTab}
185→          />
186→
187→          <div className="flex flex-1 flex-col overflow-hidden">
188→            {/* Inner tabs */}
189→            <div className="flex gap-0 border-b border-border-subtle bg-bg px-5 pt-3">
190→              {(["checkpoints", "transcript", "trails", "diff"] as const).map((tab) => (
191→                <button
192→                  key={tab}
193→                  onClick={() => setInnerTab(tab)}
194→                  className={`border-b-2 px-4 pb-2 text-xs font-medium capitalize transition-colors ${
195→                    innerTab === tab
196→                      ? "border-accent text-fg"
197→                      : "border-transparent text-fg-subtle hover:text-fg-muted"
198→                  }`}
199→                >
200→                  {tab === "checkpoints"
201→                    ? "Checkpoints"
202→                    : tab === "transcript"
203→                      ? "Transcript"
204→                      : tab === "trails"
205→                        ? "Trails"
206→                        : "Diff"}
207→                </button>
208→              ))}
209→            </div>
210→
211→            {/* Main view */}
212→            <div className="flex-1 overflow-y-auto bg-bg">
213→              {innerTab === "checkpoints" && (
214→                <CheckpointList
215→                  repoPath={activeTab.repoPath}
216→                  branch={activeTab.branch}
217→                  onSelectCheckpoint={(cp) => {
218→                    setSelectedCheckpoint(cp);
219→                    setInnerTab("transcript");
220→                  }}
221→                />
222→              )}
223→              {innerTab === "transcript" && (
224→                <TranscriptView
225→                  repoPath={activeTab.repoPath}
226→                  checkpoint={selectedCheckpoint}
227→                />
228→              )}
229→              {innerTab === "trails" && (
230→                <TrailList repoPath={activeTab.repoPath} />
231→              )}
232→              {innerTab === "diff" && (
233→                <DiffView
234→                  repoPath={activeTab.repoPath}
235→                  checkpoint={selectedCheckpoint}
236→                />
237→              )}
238→            </div>
239→
240→            {/* Resize handle */}
241→            {isTerminalOpen && (
242→              <div
243→                onMouseDown={handleResizeStart}
244→                className="h-[3px] shrink-0 cursor-row-resize bg-border transition-colors hover:bg-accent"
245→              />
246→            )}
247→
248→            {/* Terminal panel */}
249→            {isTerminalOpen && (
250→              <TerminalPanel
251→                height={terminalHeight}
252→                tab={activeTab}
