254→              />
255→            )}
256→          </div>
257→        </div>
258→      </div>
259→
260→      {!isTerminalOpen && (
261→        <button
262→          onClick={() => setIsTerminalOpen(true)}
263→          className="flex h-7 shrink-0 items-center justify-center border-t border-border bg-bg-raised text-[11px] text-fg-subtle hover:text-fg-muted"
264→        >
265→          ▲ Terminal (⌃`)
266→        </button>
267→      )}
268→    </div>
269→  );
270→}
