import { useState } from "react";
import { Search, Loader2 } from "lucide-react";
import { useCheckpointsQuery } from "../../hooks/use-tauri-query";
import type { CheckpointSummary } from "../../lib/ipc";

interface CheckpointListProps {
  repoPath: string;
  branch: string;
  onSelectCheckpoint?: (checkpoint: CheckpointSummary) => void;
}

function formatTokens(usage: CheckpointSummary["token_usage"]): string | null {
  if (!usage) return null;
  const total = usage.input_tokens + usage.output_tokens;
  if (total >= 1000) return `${(total / 1000).toFixed(1)}k tokens`;
  return `${total} tokens`;
}

function timeAgo(isoDate: string): string {
  const diff = Date.now() - new Date(isoDate).getTime();
  const mins = Math.floor(diff / 60000);
  if (mins < 1) return "just now";
  if (mins < 60) return `${mins}m ago`;
  const hours = Math.floor(mins / 60);
  if (hours < 24) return `${hours}h ago`;
  return `${Math.floor(hours / 24)}d ago`;
}

export function CheckpointList({ repoPath, branch, onSelectCheckpoint }: CheckpointListProps) {
  const { data: realCheckpoints, isLoading } = useCheckpointsQuery(repoPath, branch);

  const checkpoints = realCheckpoints ?? [];

  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [search, setSearch] = useState("");

  const filtered = search
    ? checkpoints.filter((cp) =>
        cp.commit_message.toLowerCase().includes(search.toLowerCase()) ||
        cp.checkpoint_id.toLowerCase().includes(search.toLowerCase())
      )
    : checkpoints;

  return (
    <div>
      {/* Search */}
      <div className="p-5 pb-3">
        <div className="relative">
          <Search
            size={14}
            className="absolute left-3 top-1/2 -translate-y-1/2 text-fg-subtle"
          />
          <input
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            placeholder="Search checkpoints... (⌘K)"
            className="w-full rounded-lg border border-border bg-bg-overlay py-2 pl-9 pr-3 text-[13px] text-fg outline-none transition-colors placeholder:text-fg-subtle focus:border-accent"
          />
          {isLoading && (
            <Loader2
              size={14}
              className="absolute right-3 top-1/2 -translate-y-1/2 animate-spin text-fg-subtle"
            />
          )}
        </div>
      </div>

      {/* List */}
      <div className="px-5 pb-5">
        {filtered.map((cp) => {
          const agent = cp.sessions[0]?.agent ?? null;
          const stepCount = cp.sessions.reduce((sum, s) => sum + s.step_count, 0);
          const tokens = formatTokens(cp.token_usage);
          const isManual = cp.sessions.length === 0;

          return (
            <button
              key={cp.checkpoint_id}
              onClick={() => {
                setSelectedId(cp.checkpoint_id);
                onSelectCheckpoint?.(cp);
              }}
              className={`mb-2 flex w-full gap-3.5 rounded-[10px] border p-3.5 text-left transition-all ${
                selectedId === cp.checkpoint_id
                  ? "border-accent bg-accent-bg"
                  : "border-border-subtle bg-bg-overlay hover:border-border-hover hover:bg-bg-hover"
              }`}
            >
              {/* Avatar */}
              <div className="flex h-8 w-8 shrink-0 items-center justify-center rounded-full bg-bg-hover text-sm">
                {agent ? "🤖" : "👤"}
              </div>

              {/* Content */}
              <div className="min-w-0 flex-1">
                <div className="mb-1 flex items-center gap-2">
                  <span className="truncate text-[13px] font-medium text-fg">
                    {cp.commit_message || cp.checkpoint_id}
                  </span>
                  {agent && (
                    <span
                      className={`shrink-0 rounded px-2 py-0.5 text-[10px] font-medium ${
                        agent === "Claude Code"
                          ? "bg-accent-bg text-accent-fg"
                          : "bg-green-bg text-green"
                      }`}
                    >
                      {agent}
                    </span>
                  )}
                </div>
                <div className="flex gap-3 text-[11px] text-fg-muted">
                  <span className="font-mono text-fg-subtle">
                    {cp.commit_sha ? cp.commit_sha.slice(0, 7) : cp.checkpoint_id.slice(0, 7)}
                  </span>
                  <span>{cp.files_touched.length} files</span>
                  {stepCount > 0 && <span>{stepCount} steps</span>}
                  {tokens && <span>{tokens}</span>}
                  {isManual && (
                    <span className="text-fg-subtle">manual commit</span>
                  )}
                </div>
              </div>

              {/* Time */}
              {cp.created_at && (
                <span className="shrink-0 self-start text-[11px] text-fg-subtle whitespace-nowrap">
                  {timeAgo(cp.created_at)}
                </span>
              )}
            </button>
          );
        })}

        {filtered.length === 0 && !isLoading && (
          <div className="py-12 text-center text-sm text-fg-subtle">
            No checkpoints found
          </div>
        )}
      </div>
    </div>
  );
}

