import type { Tab } from "../App";

interface TabBarProps {
  tabs: Tab[];
  activeTabId: string;
  onSelectTab: (id: string) => void;
  onCloseTab: (id: string) => void;
}

export function TabBar({
  tabs,
  activeTabId,
  onSelectTab,
  onCloseTab,
}: TabBarProps) {
  return (
    <div className="flex h-9 shrink-0 items-center border-b border-border bg-bg-raised pl-1">
      {tabs.map((tab) => {
        const isActive = tab.id === activeTabId;
        return (
          <button
            key={tab.id}
            onClick={() => onSelectTab(tab.id)}
            className={`relative flex h-full items-center gap-1.5 border-r border-border-subtle px-3.5 text-xs whitespace-nowrap transition-colors ${
              isActive
                ? "bg-bg-hover text-fg"
                : "text-fg-subtle hover:bg-bg-overlay hover:text-fg-muted"
            }`}
          >
            <span
              className={`h-[7px] w-[7px] shrink-0 rounded-full ${
                tab.hasActiveSession
                  ? "bg-green"
                  : tab.worktree
                    ? "bg-yellow"
                    : "bg-blue"
              }`}
            />
            {tab.branch}
            {tab.worktree && (
              <span className="text-[9px] text-fg-subtle">(wt)</span>
            )}
            <span
              onClick={(e) => {
                e.stopPropagation();
                onCloseTab(tab.id);
              }}
              className="ml-2 text-sm leading-none text-fg-faint hover:text-fg"
            >
              ×
            </span>
            {isActive && (
              <span className="absolute bottom-0 left-0 right-0 h-0.5 bg-accent" />
            )}
          </button>
        );
      })}
      <span className="flex h-full cursor-pointer items-center px-3 text-base text-fg-subtle hover:text-fg-muted">
        +
      </span>
    </div>
  );
}

