import { useState, useEffect } from "react";
import { Sidebar } from "./features/repos/Sidebar";
import { TitleBar } from "./components/TitleBar";
import { TabBar } from "./components/TabBar";
import { CheckpointList } from "./features/checkpoints/CheckpointList";
import { TranscriptView } from "./features/transcripts/TranscriptView";
import { TrailList } from "./features/trails/TrailList";
import { DiffView } from "./features/diff/DiffView";
import { TerminalPanel } from "./features/terminal/TerminalPanel";
import { useLiveUpdates } from "./hooks/use-live-updates";
import type { BranchInfo, CheckpointSummary, WorktreeInfo } from "./lib/ipc";

export interface Tab {
  id: string;
  branch: string;
  repoPath: string;
  worktree: WorktreeInfo | null;
  hasActiveSession: boolean;
}

export default function App() {
  const [tabs, setTabs] = useState<Tab[]>([
    {
      id: "main",
      branch: "main",
      repoPath: "",
      worktree: null,
      hasActiveSession: false,
    },
  ]);
  const [activeTabId, setActiveTabId] = useState("main");
  const [terminalHeight, setTerminalHeight] = useState(
    () => Number(localStorage.getItem("entire:terminal-height")) || 220
  );
  const [isTerminalOpen, setIsTerminalOpen] = useState(
    () => localStorage.getItem("entire:terminal-open") !== "false"
  );
  const [innerTab, setInnerTab] = useState<
    "checkpoints" | "transcript" | "trails" | "diff"
  >("checkpoints");
  const [selectedCheckpoint, setSelectedCheckpoint] =
    useState<CheckpointSummary | null>(null);

  const activeTab = tabs.find((t) => t.id === activeTabId) ?? tabs[0];

  // Live updates — watch active repo for checkpoint/session changes
  useLiveUpdates(activeTab.repoPath);

  // Persist UI state to localStorage
  useEffect(() => {
    localStorage.setItem("entire:terminal-height", String(terminalHeight));
  }, [terminalHeight]);
  useEffect(() => {
    localStorage.setItem("entire:terminal-open", String(isTerminalOpen));
  }, [isTerminalOpen]);

  // Keyboard shortcuts
  useEffect(() => {
    function onKeyDown(e: KeyboardEvent) {
      const meta = e.metaKey || e.ctrlKey;

      // Cmd+K = focus search
      if (meta && e.key === "k") {
        e.preventDefault();
        document.querySelector<HTMLInputElement>('input[placeholder*="Search"]')?.focus();
      }
      // Ctrl+` = toggle terminal
      if (e.ctrlKey && e.key === "`") {
        e.preventDefault();
        setIsTerminalOpen((v) => !v);
      }
      // Cmd+W = close active tab
      if (meta && e.key === "w") {
        e.preventDefault();
        handleCloseTab(activeTabId);
      }
      // Cmd+1-9 = switch to tab by index
      if (meta && e.key >= "1" && e.key <= "9") {
        e.preventDefault();
        const idx = parseInt(e.key) - 1;
        if (idx < tabs.length) {
          setActiveTabId(tabs[idx].id);
        }
      }
      // Cmd+[ / Cmd+] = prev/next tab
      if (meta && e.key === "[") {
        e.preventDefault();
        const idx = tabs.findIndex((t) => t.id === activeTabId);
        if (idx > 0) setActiveTabId(tabs[idx - 1].id);
      }
      if (meta && e.key === "]") {
        e.preventDefault();
        const idx = tabs.findIndex((t) => t.id === activeTabId);
        if (idx < tabs.length - 1) setActiveTabId(tabs[idx + 1].id);
      }
    }
    window.addEventListener("keydown", onKeyDown);
    return () => window.removeEventListener("keydown", onKeyDown);
  }, [activeTabId, tabs]);

  function handleBranchSelect(branch: BranchInfo, repoPath: string) {
    const existing = tabs.find(
      (t) => t.branch === branch.name && t.repoPath === repoPath
    );
    if (existing) {
      setActiveTabId(existing.id);
    } else {
      const newTab: Tab = {
        id: `${repoPath}:${branch.name}`,
        branch: branch.name,
        repoPath,
        worktree: null,
        hasActiveSession: false,
      };
      setTabs([...tabs, newTab]);
      setActiveTabId(newTab.id);
    }
  }

  function handleWorktreeSelect(wt: WorktreeInfo, repoPath: string) {
    const existing = tabs.find(
      (t) => t.branch === wt.branch && t.repoPath === repoPath
    );
    if (existing) {
      setActiveTabId(existing.id);
    } else {
      const newTab: Tab = {
        id: `${repoPath}:${wt.branch}`,
        branch: wt.branch,
        repoPath,
        worktree: wt,
        hasActiveSession: false,
      };
      setTabs([...tabs, newTab]);
      setActiveTabId(newTab.id);
    }
  }

  function handleCloseTab(tabId: string) {
    if (tabs.length <= 1) return;
    const idx = tabs.findIndex((t) => t.id === tabId);
    const newTabs = tabs.filter((t) => t.id !== tabId);
    setTabs(newTabs);
    if (activeTabId === tabId) {
      setActiveTabId(newTabs[Math.max(0, idx - 1)].id);
    }
  }

  function handleResizeStart(e: React.MouseEvent) {
    e.preventDefault();
    const startY = e.clientY;
    const startHeight = terminalHeight;

    function onMouseMove(ev: MouseEvent) {
      const delta = startY - ev.clientY;
      setTerminalHeight(Math.max(100, Math.min(600, startHeight + delta)));
    }
    function onMouseUp() {
      window.removeEventListener("mousemove", onMouseMove);
      window.removeEventListener("mouseup", onMouseUp);
    }
    window.addEventListener("mousemove", onMouseMove);
    window.addEventListener("mouseup", onMouseUp);
  }

  return (
    <div className="flex h-screen flex-col">
      <TitleBar title={`Entire — ${activeTab?.branch ?? ""}`} />

      <div className="flex flex-1 overflow-hidden">
        {/* Sidebar */}
        <Sidebar
          activeTab={activeTab}
          onBranchSelect={handleBranchSelect}
          onWorktreeSelect={handleWorktreeSelect}
        />

        {/* Main content */}
        <div className="flex flex-1 flex-col overflow-hidden">
          <TabBar
            tabs={tabs}
            activeTabId={activeTabId}
            onSelectTab={setActiveTabId}
            onCloseTab={handleCloseTab}
          />

          <div className="flex flex-1 flex-col overflow-hidden">
            {/* Inner tabs */}
            <div className="flex gap-0 border-b border-border-subtle bg-bg px-5 pt-3">
              {(["checkpoints", "transcript", "trails", "diff"] as const).map((tab) => (
                <button
                  key={tab}
                  onClick={() => setInnerTab(tab)}
                  className={`border-b-2 px-4 pb-2 text-xs font-medium capitalize transition-colors ${
                    innerTab === tab
                      ? "border-accent text-fg"
                      : "border-transparent text-fg-subtle hover:text-fg-muted"
                  }`}
                >
                  {tab === "checkpoints"
                    ? "Checkpoints"
                    : tab === "transcript"
                      ? "Transcript"
                      : tab === "trails"
                        ? "Trails"
                        : "Diff"}
                </button>
              ))}
            </div>

            {/* Main view */}
            <div className="flex-1 overflow-y-auto bg-bg">
              {innerTab === "checkpoints" && (
                <CheckpointList
                  repoPath={activeTab.repoPath}
                  branch={activeTab.branch}
                  onSelectCheckpoint={(cp) => {
                    setSelectedCheckpoint(cp);
                    setInnerTab("transcript");
                  }}
                />
              )}
              {innerTab === "transcript" && (
                <TranscriptView
                  repoPath={activeTab.repoPath}
                  checkpoint={selectedCheckpoint}
                />
              )}
              {innerTab === "trails" && (
                <TrailList repoPath={activeTab.repoPath} />
              )}
              {innerTab === "diff" && (
                <DiffView
                  repoPath={activeTab.repoPath}
                  checkpoint={selectedCheckpoint}
                />
              )}
            </div>

            {/* Resize handle */}
            {isTerminalOpen && (
              <div
                onMouseDown={handleResizeStart}
                className="h-[3px] shrink-0 cursor-row-resize bg-border transition-colors hover:bg-accent"
              />
            )}

            {/* Terminal panel */}
            {isTerminalOpen && (
              <TerminalPanel
                height={terminalHeight}
                tab={activeTab}
                onToggle={() => setIsTerminalOpen(false)}
              />
            )}
          </div>
        </div>
      </div>

      {!isTerminalOpen && (
        <button
          onClick={() => setIsTerminalOpen(true)}
          className="flex h-7 shrink-0 items-center justify-center border-t border-border bg-bg-raised text-[11px] text-fg-subtle hover:text-fg-muted"
        >
          ▲ Terminal (⌃`)
        </button>
      )}
    </div>
  );
}
